#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#define OW_PIN 2
#define SD_CS 10
#define TEC_EN 9
#define TEC_DIR 7
#define SSR_PIN 8
#define TOL 1.0f
#define N_ZONES 4
OneWire ow(OW_PIN); DallasTemperature ds(&ow); File lg;
float targets[N_ZONES]={60.0f,45.0f,30.0f,20.0f};
unsigned long holds[N_ZONES]={300000UL,300000UL,300000UL,300000UL};
int g_zone=0; unsigned long g_zs=0;
bool cooling_profile_step(float*tgts,unsigned long*hlds,int n,int*zone,unsigned long*zs,float pv,float tol){
  if(*zone>=n) return true;
  float sp=tgts[*zone];
  bool atSP=fabs(pv-sp)<=tol;
  if(atSP&&millis()-*zs>hlds[*zone]){(*zone)++;*zs=millis();}
  else if(!atSP)*zs=millis();
  return(*zone>=n);
}
void initHardware(){
  pinMode(TEC_EN,OUTPUT);pinMode(TEC_DIR,OUTPUT);pinMode(SSR_PIN,OUTPUT);
  ds.begin();SD.begin(SD_CS);
  lg=SD.open("xtal.csv",FILE_WRITE);
  if(lg)lg.println("t_s,zone,Tsp,T_C,plateau");
  Serial.begin(9600);g_zs=millis();
}
float readTemperatureSensor(){ds.requestTemperatures();return ds.getTempCByIndex(0);}
void tecCoolingControl(float sp,float pv){
  if(pv>sp+TOL){digitalWrite(TEC_DIR,HIGH);analogWrite(TEC_EN,min((int)(20*(pv-sp)),255));digitalWrite(SSR_PIN,HIGH);}
  else if(pv<sp-TOL){digitalWrite(TEC_DIR,LOW);analogWrite(TEC_EN,100);digitalWrite(SSR_PIN,LOW);}
  else{analogWrite(TEC_EN,0);digitalWrite(SSR_PIN,LOW);}
}
void logDataSD(unsigned long t,int z,float sp,float T,bool plateau){
  if(lg){lg.print(t);lg.print(',');lg.print(z);lg.print(',');lg.print(sp,1);lg.print(',');lg.print(T,2);lg.print(',');lg.println(plateau?1:0);lg.flush();}
  Serial.print("Z=");Serial.print(z);Serial.print(" T=");Serial.println(T,2);
}
bool detectPlateau(float T,float*prevT,float thresh){
  bool p=fabs(T-*prevT)<thresh;*prevT=T;return p;
}
void setup(){initHardware();}
void loop(){
  static unsigned long prev=0;static float prevT=0;
  unsigned long now=millis();
  if(now-prev<1000)return;prev=now;
  float T=readTemperatureSensor();
  bool done=cooling_profile_step(targets,holds,N_ZONES,&g_zone,&g_zs,T,TOL);
  if(done){analogWrite(TEC_EN,0);lg.close();Serial.println("DONE");while(1);}
  float sp=targets[g_zone];
  tecCoolingControl(sp,T);
  bool plateau=detectPlateau(T,&prevT,0.05f);
  logDataSD(now/1000,g_zone,sp,T,plateau);
}
